+  const url = `${GEMINI_BASE}/models/${GEMINI_MODEL}:generateContent?key=${apiKey}`;
+
+  const contents: Content[] = [...history, { role: 'user', parts: [{ text: newUserText }] }];
+
+  const body = {
+    contents,
+    tools: [{ google_search: {} }, { url_context: {} }],
+    generationConfig: { temperature: 1.0 },
+  };
