+  <style>
+    /* 
+      1. Global Opt-In
+      The document defaults to the user's system preference. 
+    */
+    :root {
+      color-scheme: light dark;
+
+      /* Global base styles for the page body, strictly for contrast against the component */
+      --page-bg: light-dark(#e8eaed, #1c1c1e);
+      --page-text: light-dark(#202124, #e8eaed);
+    }
+
+    body {
+      font-family: system-ui, -apple-system, sans-serif;
+      padding: 2rem;
+      margin: 0;
+      display: flex;
+      flex-direction: column;
+      align-items: center;
+      min-height: 100vh;
+      background-color: var(--page-bg);
+      color: var(--page-text);
+      transition: background-color 0.3s, color 0.3s;
+    }
+
+    h1,
+    p.description {
+      text-align: center;
+      max-width: 600px;
+    }
+
+    p.description {
+      margin-bottom: 2rem;
+      line-height: 1.6;
+    }
+
+    /* 
+      ===============================================================
+      2. The Component-Specific Theme Definition
+      ===============================================================
+      Instead of declaring `light-dark()` variables on the `:root`, 
+      we define a class containing our semantic variables!
+    */
+    .themed-card {
+
+      --card-bg: light-dark(#ffffff, #2d2e31);
